	/**
	 * Get SVG path data for a given icon name.
	 *
	 * @param string $icon_name Icon name without 'fa-' prefix (e.g. 'certificate').
	 * @return array|null Array with 'viewBox' and 'd' keys, or null if not found.
	 */
	public static function get( string $icon_name ): ?array {
		return self::ICON_PATHS[ $icon_name ] ?? null;
	}

	/**
	 * Get an inline SVG element for the given icon.
	 *
	 * @param string $icon_name  Icon name without 'fa-' prefix.
	 * @param string $class      Optional CSS class for the SVG element.
	 * @param string $size       Width/height attribute value (default '1em').
	 * @return string SVG markup or empty string if icon not found.
	 */
	public static function svg( string $icon_name, string $class = '', string $size = '1em' ): string {
		$icon = self::get( $icon_name );
		if ( ! $icon ) {
			return '';
		}

		$class_attr = $class ? ' class="' . esc_attr( $class ) . '"' : '';

		return sprintf(
			'<svg xmlns="http://www.w3.org/2000/svg" viewBox="%s" width="%s" height="%s" fill="currentColor" aria-hidden="true"%s><path d="%s"/></svg>',
			esc_attr( $icon['viewBox'] ),
			esc_attr( $size ),
			esc_attr( $size ),
			$class_attr,
			esc_attr( $icon['d'] )
		);
	}
